import{_ as a,o as n,c as o,ak as t}from"./chunks/framework.CRYrbBns.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"1 - Installation.md","filePath":"1 - Installation.md"}'),r={name:"1 - Installation.md"};function i(l,e,s,c,d,u){return n(),o("div",null,[...e[0]||(e[0]=[t('<p>Le logiciel <strong>conda</strong> permet d&#39;utiliser un environnement virtuel python.</p><blockquote><p>⚠️ <strong>Il faut activer cet environnement à chaque utilisation du robot.</strong></p></blockquote><hr><h2 id="installation" tabindex="-1">Installation : <a class="header-anchor" href="#installation" aria-label="Permalink to “Installation :”">​</a></h2><ol><li>Se rendre sur : &quot;<a href="https://github.com/conda-forge/miniforge" target="_blank" rel="noreferrer">https://github.com/conda-forge/miniforge</a>&quot;</li><li>Dans la section <strong>Releases</strong>, puis <strong>Assets</strong>, sélectionner l&#39;installateur adapté à votre système d&#39;exploitation.</li><li>Lancer l&#39;exécutable (installeur)</li><li>Une fois l&#39;installation terminée, lancer : <code>conda create -y -n lerobot python=3.10</code></li><li>Lancer l&#39;environnement Conda</li></ol><h3 id="erreur-rencontre-lors-du-lancement-de-l-environnement-conda" tabindex="-1">Erreur rencontré lors du lancement de l&#39;environnement Conda : <a class="header-anchor" href="#erreur-rencontre-lors-du-lancement-de-l-environnement-conda" aria-label="Permalink to “Erreur rencontré lors du lancement de l&#39;environnement Conda :”">​</a></h3><p>La commande suivante n&#39;a jamais fonctionné pour nous : <code>conda activate lerobot</code></p><h3 id="solutions" tabindex="-1">Solutions : <a class="header-anchor" href="#solutions" aria-label="Permalink to “Solutions :”">​</a></h3><hr><h5 id="sur-windows" tabindex="-1">Sur Windows : <a class="header-anchor" href="#sur-windows" aria-label="Permalink to “Sur Windows :”">​</a></h5><p><code>call C:\\Users\\&lt;votre_utilisateur&gt;\\miniforge3\\Scripts\\activate.bat lerobot</code></p><blockquote><p>Remplacez &lt;votre_utilisateur&gt; par votre nom d&#39;utilisateur Windows.</p></blockquote><h5 id="sur-linux" tabindex="-1">Sur Linux : <a class="header-anchor" href="#sur-linux" aria-label="Permalink to “Sur Linux :”">​</a></h5><p><code>eval &quot;$(conda shell.bash hook)&quot;</code><code>conda activate lerobot</code></p><h5 id="sur-raspberry-pi" tabindex="-1">Sur Raspberry-pi : <a class="header-anchor" href="#sur-raspberry-pi" aria-label="Permalink to “Sur Raspberry-pi :”">​</a></h5><p>Sur raspberry-pi, le logiciel installé n&#39;est pas conda, mais <strong>micromamba</strong>. <code>eval &quot;$(micromamba shell hook --shell bash)&quot;</code><code>micromamba activate lerobot</code></p><hr><h2 id="finalisation-de-l-installation" tabindex="-1">Finalisation de l&#39;installation <a class="header-anchor" href="#finalisation-de-l-installation" aria-label="Permalink to “Finalisation de l&#39;installation”">​</a></h2><ol start="6"><li><p>Une fois l&#39;environnement lancé : exécuter la commande : <code>conda install ffmpeg -c conda-forge</code> <a href="https://www.ffmpeg.org/" target="_blank" rel="noreferrer">Plus d&#39;infos sur la librairie FFMPEG</a></p></li><li><p><code>pip install lerobot</code> permettant l&#39;installation de l&#39;ensemble des librairies nécessaires au robot.</p></li></ol><p>✅ <strong>L&#39;installation est terminée !</strong> Prochaine étape : <a href="/2 - Configuration et calibration des servos moteurs.html">2 - Configuration et calibration des servos moteurs</a></p>',20)])])}const h=a(r,[["render",i]]);export{p as __pageData,h as default};
